import { callMcpSkill } from "@/lib/ai/skills/mcp";

const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

export async function main() {
  const result = await callMcpSkill({
    toolId,
    toolName: "find_arbitrage_opportunities",
    args: {
      category: "politics",
      limit: 20
    }
  });

  const arbitrageOpportunities = Array.isArray(result?.arbitrageOpportunities)
    ? result.arbitrageOpportunities
    : [];
  const wideSpreadMarkets = Array.isArray(result?.wideSpreadMarkets)
    ? result.wideSpreadMarkets
    : [];

  const passiveOrderCandidates = [
    ...arbitrageOpportunities.map((m) => ({
      market: m.market,
      url: m.url,
      type: "arbitrage",
      totalCost: m.totalCost,
      potentialEdge: m.potentialEdge,
      edgePercent: m.edgePercent,
      note: m.note
    })),
    ...wideSpreadMarkets.map((m) => ({
      market: m.market,
      url: m.url,
      type: "wide_spread",
      spread: m.spread,
      midPrice: m.midPrice,
      spreadPercent: m.spreadPercent
    }))
  ].slice(0, 10);

  const worthWorkingWithPassiveOrders = passiveOrderCandidates.filter((m) => {
    if (m.type === "arbitrage") return typeof m.totalCost === "number" && m.totalCost < 1;
    if (m.type === "wide_spread") return typeof m.spread === "number" && m.spread > 0;
    return false;
  });

  return {
    fetchedAt: result?.fetchedAt,
    summary: result?.summary,
    methodology: result?.methodology,
    arbitrageOpportunities,
    wideSpreadMarkets,
    passiveOrderCandidates: worthWorkingWithPassiveOrders,
    note:
      worthWorkingWithPassiveOrders.length > 0
        ? "Passive order candidates are those with verified sub-$1 arbitrage or the widest live spreads in politics."
        : "No verified passive-order candidates found in the current scan."
  };
}

