import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  // Probe: fetch broad politics candidates and live top-liquidity markets in parallel
  const probeBatch = await callMcpSkillsParallel({
    label: "probe-politics-event-candidates",
    calls: [
      {
        key: "categoryBrowse",
        toolId,
        toolName: "browse_category",
        args: {
          category: "politics",
          sortBy: "liquidity",
          limit: 25,
          includeResolved: false
        }
      },
      {
        key: "topMarkets",
        toolId,
        toolName: "get_top_markets",
        args: {
          category: "politics",
          sortBy: "liquidity",
          limit: 25,
          includeNearResolved: false,
          includeEnded: false
        }
      }
    ]
  });

  const categoryBrowse = probeBatch.results.find((r) => r.key === "categoryBrowse");
  const topMarkets = probeBatch.results.find((r) => r.key === "topMarkets");

  const browseData = categoryBrowse && categoryBrowse.status === "fulfilled" ? categoryBrowse.value : null;
  const topMarketsData = topMarkets && topMarkets.status === "fulfilled" ? topMarkets.value : null;

  const browseEvents = Array.isArray(browseData?.events) ? browseData.events : [];
  const marketRows = Array.isArray(topMarketsData?.markets) ? topMarketsData.markets : [];

  const combinedCandidates = [
    ...browseEvents.map((e) => ({
      slug: e?.slug,
      title: e?.title,
      liquidity: e?.liquidity,
      marketsCount: e?.marketsCount,
      source: "browse_category"
    })),
    ...marketRows.map((m) => ({
      slug: m?.slug,
      title: m?.eventTitle || m?.title,
      liquidity: m?.liquidity,
      marketsCount: 1,
      source: "get_top_markets"
    }))
  ].filter((x) => x.slug && x.title);

  if (combinedCandidates.length === 0) {
    return {
      stopReason: "no_live_politics_candidates",
      missingData: ["live politics candidates"],
      attemptedBranches: ["browse_category", "get_top_markets"],
      probeTelemetry: probeBatch.summary
    };
  }

  // Decide: deterministic semantic targeting to choose a representative, high-liquidity multi-outcome event
  const rankedCandidates = pickTopSemanticCandidates({
    target: "most liquid live multi-outcome politics event",
    candidates: combinedCandidates,
    requiredTerms: ["politics"],
    avoidTerms: ["resolved", "closed"],
    limit: 8
  });

  const shortlist = rankedCandidates
    .map((c) => c?.candidate || c)
    .filter((c) => c && c.slug && c.title);

  const multiOutcomeShortlist = shortlist.filter((c) => (typeof c.marketsCount === "number" ? c.marketsCount > 1 : true));

  const seedCandidates = (multiOutcomeShortlist.length > 0 ? multiOutcomeShortlist : shortlist).slice(0, 5);

  let chosenEvent = null;
  let chosenOutcomes = [];

  // Execute: shortlist-first sequential resolution until we find a live multi-outcome event
  for (const candidate of seedCandidates) {
    const resolved = await callMcpSkill({
      toolId,
      toolName: "search_and_get_outcomes",
      args: {
        query: candidate.title,
        category: "politics",
        sortBy: "volume"
      }
    });

    const outcomes = Array.isArray(resolved?.outcomes) ? resolved.outcomes : [];
    if (resolved?.eventTitle && outcomes.length > 1) {
      chosenEvent = {
        slug: resolved.eventSlug || candidate.slug,
        title: resolved.eventTitle,
        url: resolved.eventUrl || null,
        liquidity: candidate.liquidity ?? null,
        source: candidate.source
      };
      chosenOutcomes = outcomes;
      break;
    }
  }

  if (!chosenEvent || chosenOutcomes.length === 0) {
    return {
      stopReason: "no_resolved_multi_outcome_event_found",
      missingData: ["resolved multi-outcome event"],
      attemptedBranches: seedCandidates.map((c) => c.title),
      probeTelemetry: probeBatch.summary
    };
  }

  // Rank the discovered outcomes by current price and select the top four favorites explicitly
  const topFourByPrice = [...chosenOutcomes]
    .filter((o) => o && o.tokenId && typeof o.price === "number")
    .sort((a, b) => b.price - a.price)
    .slice(0, 4);

  const tokenIds = topFourByPrice.map((o) => o.tokenId);

  // Batch independent read-only quote fields across a different endpoint before local packaging
  const quoteBatch = await callMcpSkillsParallel({
    label: "event-outcome-quotes",
    calls: [
      {
        key: "spreads",
        toolId,
        toolName: "get_spreads",
        args: { tokenIds }
      },
      {
        key: "midpoints",
        toolId,
        toolName: "get_midpoints",
        args: { tokenIds }
      }
    ]
  });

