    toolId,
    toolName: "summarize_live_market_activity",
    args: {
      sortBy: "ending_soon",
      tradeLimit: 20
    }
  });

  const recentTrades = Array.isArray(result?.recentTrades) ? result.recentTrades : [];
  const tradesSummary = result?.tradesSummary || {};
  const selectedMarket = result?.selectedMarket || {};
  const openInterest = result?.openInterest || {};
  const totalTrades = typeof tradesSummary.totalTrades === "number" ? tradesSummary.totalTrades : 0;
  const totalVolume = typeof tradesSummary.totalVolume === "number" ? tradesSummary.totalVolume : 0;
  const buyVolume = typeof tradesSummary.buyVolume === "number" ? tradesSummary.buyVolume : 0;
  const sellVolume = typeof tradesSummary.sellVolume === "number" ? tradesSummary.sellVolume : 0;
  const oiValue = typeof openInterest.value === "number" ? openInterest.value : null;

  const buySellImbalance = totalVolume > 0 ? (buyVolume - sellVolume) / totalVolume : null;
  const hasEnoughActivity = totalTrades >= 10 && totalVolume > 0;

  let tapeRead = "noise";
  if (hasEnoughActivity) {
    if (buySellImbalance !== null && Math.abs(buySellImbalance) >= 0.2 && oiValue !== null && oiValue > totalVolume) {
      tapeRead = buySellImbalance > 0 ? "genuine bullish conviction" : "genuine bearish conviction";
    } else if (buySellImbalance !== null && Math.abs(buySellImbalance) >= 0.2) {
      tapeRead = buySellImbalance > 0 ? "moderate bullish conviction" : "moderate bearish conviction";
    } else {
      tapeRead = "mostly noise / two-sided churn";
    }
  }

  return {
    market: {
      title: selectedMarket.title || null,
      slug: selectedMarket.slug || null,
      conditionId: selectedMarket.conditionId || null,
      url: selectedMarket.url || null,
      endDate: selectedMarket.endDate || null,
      category: selectedMarket.category || null,
      selectionReason: selectedMarket.selectionReason || null
    },
    activity: {
      totalTrades,
      totalVolume,
      buyVolume,
      sellVolume,
      avgPrice: typeof tradesSummary.avgPrice === "number" ? tradesSummary.avgPrice : null,
      openInterest: oiValue,
      recentTradesCount: recentTrades.length
    },
    interpretation: {
      tapeRead,
      convictionSignal:
        totalTrades === 0
          ? "insufficient data"
          : tapeRead,
      note:
        totalTrades === 0
          ? "No recent trades were returned for the selected live market."
          : "Interpretation is based on recent trade balance and open interest versus recent volume."
    },
    recentTrades: recentTrades.slice(0, 10),
    fetchedAt: result?.fetchedAt || null
  };
}

